import{_ as i,o as s,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"86. Skill Mix","description":"","frontmatter":{"title":"86. Skill Mix","eba":"Nurses and Midwives 2024-2028","topics":["staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/86-skill-mix.md","filePath":"ebas/nurses-midwives/classification-staffing/86-skill-mix.md"}'),a={name:"ebas/nurses-midwives/classification-staffing/86-skill-mix.md"};function n(l,e,o,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_86-skill-mix" tabindex="-1">86. Skill Mix <a class="header-anchor" href="#_86-skill-mix" aria-label="Permalink to &quot;86. Skill Mix&quot;">​</a></h1><p><strong>(a)</strong> The minimum skill mix that each Employer in respect of the hospitals specified in Schedule 2 of the Safe Patient Care Act aims to achieve in all acute/general surgical and medical wards is:</p><p><strong>(i)</strong> 1/3 Registered Nurse with more than three years&#39; experience;</p><p><strong>(ii)</strong> 1/3 Registered Nurse with one to three years&#39; experience; and</p><p><strong>(iii)</strong> 1/3 Registered Nurse with graduate nurse/Enrolled Nurse.</p><p><strong>(b)</strong> From 1 January 2025, the minimum skill mix that each Employer aims to achieve in all operating theatres and paediatric wards is:</p><p><strong>(i)</strong> 1/3 Registered Nurse with more than three years&#39; experience;</p><p><strong>(ii)</strong> 1/3 Registered Nurse with one to three years&#39; experience; and</p><p><strong>(iii)</strong> 1/3 graduate Registered Nurse/Enrolled Nurse.</p><p>Plain language terms: skill mix, ratios, nurse mix.</p>',10)])])}const h=i(a,[["render",n]]);export{g as __pageData,h as default};
